@spec tv_fx_region_spec  src=tests/specs/tv_fx_region_spec.lua  loc=925  sha=52a5eef  cases=47
@exercises dataStore (h.ds), trackerManager (h.tm), midiManager (h.fm), trackerView (h.vm), editCursor (h.ec), commandManager (h.cmgr), clipboard (h.clipboard)
@surface   ds:assign, tm:rebuild, ds:get, tm:flush, fm:dump, vm:setGridSize, vm:ppqToRow, ec:setPos, vm:fxHostForEdit, tm:addEvent, vm:noteFx, vm:setNoteFx, vm:removeFxStage, vm:addFxStage, vm:setFxField, vm:rowToPPQ, vm:fxHostAtCursor, cmgr:invoke, tm:getChannel, vm:editEvent, tm:subscribe, ec:row, ec:extendTo, clipboard:collect
@harness   mk

# Intent
  Track B (note macros v2): the fx-region column + Super-X addressing. A region
  renders as a tailed kind-badge in a per-channel fx column, and the v1 note-FX
  editor addresses it by uuid. see design/note-macros-v2.md § Authoring and editing the fx

# Helpers
  @fn injectRegion(h, over)  @ 11-16
  @fn fxColFor(h, chan)  @ 18-22
  @fn region(h, uuid)  @ 24-28
  @fn noteColIdx(h, chan)  @ 30-34
  @fn addNote(h)  @ 36-40
  @fn authoredUuid(h)  @ 42-44
  @fn authoredPitches(h)  @ 48-55
      -- Pitches still sounding on the take (non-derived). Empty once a replace region has
      -- parked the covered chord off-take.

# Cases
  @case 'a region materialises a per-channel fx column with a badge + tail'  [harness]  @ 62-74
  @case 'no region -> no fx column'  [harness]  @ 78-84
  @case 'an empty-fx region renders no column (it is an inert husk)'  [harness]  @ 88-94
  @case 'two overlapping regions pack into separate fx columns, each addressable'  [harness]  @ 100-128
  @case 'two disjoint regions share one fx column (packed into lane 1)'  [harness]  @ 132-144
  @case 'replace region: a parked note still renders in its note column'  [harness]  @ 150-162
  @case 'replace region: a parked cc still renders in its cc column'  [harness]  @ 166-189
  @case 'noteFx resolves a region uuid to its fx list'  [harness]  @ 195-200
  @case 'setNoteFx writes a region fx list back to ds'  [harness]  @ 204-210
  @case 'setNoteFx REMOVE deletes the region (a region is its fx)'  [harness]  @ 214-220
  @case 'region fx: deselecting the last kind keeps a husk the editor can repopulate'  [harness]  @ 224-234
  @case 'setFxField edits one region fx field, leaving the region'  [harness]  @ 238-244
  @case 'fxHostForEdit: caret on an fx cell returns the region uuid'  [harness]  @ 250-258
  @case 'fxHostForEdit: a selection mints a replace region over its span'  [harness]  @ 262-276
  @case 'fxHostAtCursor: a selection does not mint -- cursor movement has no side effect'  [harness]  @ 280-288
  @case 'fxHostAtCursor: caret anywhere in an fx region returns its uuid, nil past the tail'  [harness]  @ 292-305
  @case 'fxHostForEdit: off a note with no selection is nil; on a note, its uuid (v1)'  [harness]  @ 309-319
  @case 'parked note: a pitch nudge edits the off-take stash and re-renders, still parked'  [harness]  @ 325-339
  @case 'parked note: delete removes it from the stash and does not restore it when the window moves off'  [harness]  @ 343-354
  @case 'parked add: typing a note into a replace window stashes a logical spec, off the take'  [harness]  @ 358-373
  @case 'parked move-out: nudging a parked note past the window end restores it to the take'  [harness]  @ 377-390
  @case 'parked cc: a value nudge edits the off-take cc stash; delete removes it'  [harness]  @ 394-426
  @case 'parked pb: a value nudge edits the off-take pb stash; delete removes it'  [harness]  @ 430-466
  @case 'multi-select spanning a parked note and a take note: both edit under one rebuild'  [harness]  @ 470-491
  @case 'fx noteOff truncates the region tail to the cursor row'  [harness]  @ 497-509
  @case 'fx noteOff finds the right region in its lane when cells are in storage, not ppq, order'  [harness]  @ 513-527
  @case 'fx noteOff past the region tail grows it to the cursor row'  [harness]  @ 531-540
  @case 'fx noteOff on the onset row is a no-op (deletion is the delete verb, not noteOff)'  [harness]  @ 544-555
  @case 'fx noteOff on the window end row re-opens it to the pattern length'  [harness]  @ 559-569
  @case 'fx growNote / shrinkNote resize the region from its end'  [harness]  @ 573-584
  @case 'fx nudgeForward shifts the whole window and the caret follows'  [harness]  @ 588-600
  @case 'fx nudge keeps the moved region in its lane; the newly-overlapped sibling displaces right'  [harness]  @ 604-626
  @case 'fx nudge of an already-overlapping region keeps its own higher lane (no reorder)'  [harness]  @ 630-649
  @case 'fx nudge that makes an overlap disjoint tracks the caret across the column merge'  [harness]  @ 653-673
  @case 'fx window edit on a disjoint region does not churn storage order'  [harness]  @ 677-693
  @case 'fx nudgeBack refuses at the top grid edge (window unchanged)'  [harness]  @ 697-708
  @case 'fx eventShiftLeft swaps the region one lane left, flipping storage precedence'  [harness]  @ 714-738
  @case 'fx eventShiftRight swaps the region one lane right (the inverse move)'  [harness]  @ 742-757
  @case 'fx eventShift is a no-op at the grid edge (lone region, nothing beside it)'  [harness]  @ 761-773
  @case 'fx eventShift no-ops when the adjacent lane is empty at the cursor row'  [harness]  @ 777-792
  @case 'parked note: noteOff shortens its tail in the stash, stays parked'  [harness]  @ 798-811
  @case 'parked note: a time nudge within the window retimes the stash, stays parked'  [harness]  @ 815-828
  @case 'fx copy captures a region by onset; the whole window rides, tail spilling past the band'  [harness]  @ 834-852
  @case 'fx copy skips a region that only passes through the band (onset above it)'  [harness]  @ 856-865
  @case 'fx copy + paste stacks a duplicate region at the cursor row, original intact'  [harness]  @ 869-889
  @case 'fx delete removes the region under the caret'  [harness]  @ 893-902
  @case 'fx deleteSel drops every region the rectangle catches (onset in band), sparing the rest'  [harness]  @ 906-923

